package com.pinova.api.controller;import com.pinova.api.response.AdminAuditResponse;import com.pinova.api.web.CurrentAdminResolver;import com.pinova.common.api.ApiResponse;import com.pinova.service.AdminOperationAuditService;import jakarta.servlet.http.HttpServletRequest;import org.springframework.web.bind.annotation.*;import java.util.List;
@RestController @RequestMapping("/admin/audits") public class AdminAuditController{private final AdminOperationAuditService service;private final CurrentAdminResolver resolver;public AdminAuditController(AdminOperationAuditService s,CurrentAdminResolver r){service=s;resolver=r;}@GetMapping public ApiResponse<List<AdminAuditResponse>> list(@RequestParam(required=false)String domainCode,@RequestParam(required=false)String actionCode,HttpServletRequest r){return ApiResponse.success(service.list(resolver.requireCurrentAdmin(r),domainCode,actionCode).stream().map(a->new AdminAuditResponse(String.valueOf(a.id()),String.valueOf(a.operatorId()),a.domainCode(),a.actionCode(),a.targetType(),a.targetId(),a.requestId(),a.reason(),a.beforeSnapshot(),a.afterSnapshot(),a.occurredAt())).toList());}}
